1	{{/*
2	Expand the name of the chart.
3	*/}}
4	{{- define "pawtograder.name" -}}
5	{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" -}}
6	{{- end -}}
7	
