13	{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" -}}
14	{{- else -}}
15	{{- $name := default .Chart.Name .Values.nameOverride -}}
16	{{- if contains $name .Release.Name -}}
17	{{- .Release.Name | trunc 63 | trimSuffix "-" -}}
18	{{- else -}}
19	{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" -}}
20	{{- end -}}
21	{{- end -}}
22	{{- end -}}
23	
24	{{/*
25	Per-component name: <fullname>-<component>.
26	Usage: {{ include "pawtograder.componentName" (dict "ctx" . "component" "postgres") }}
27	*/}}
28	{{- define "pawtograder.componentName" -}}
29	{{- printf "%s-%s" (include "pawtograder.fullname" .ctx) .component | trunc 63 | trimSuffix "-" -}}
30	{{- end -}}
31	
32	{{/*
33	Chart label string.
34	*/}}
35	{{- define "pawtograder.chart" -}}
36	{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" -}}
37	{{- end -}}
38	
39	{{/*
40	Common labels stamped on every resource.
41	*/}}
42	{{- define "pawtograder.labels" -}}
43	helm.sh/chart: {{ include "pawtograder.chart" . }}
44	{{ include "pawtograder.selectorLabels" . }}
45	{{- if .Chart.AppVersion }}
46	app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
