71	{{/*
72	Per-component selector labels.
73	*/}}
74	{{- define "pawtograder.componentSelectorLabels" -}}
75	{{ include "pawtograder.selectorLabels" .ctx }}
76	app.kubernetes.io/component: {{ .component }}
77	{{- end -}}
78	
79	{{/*
80	ServiceAccount name.
81	*/}}
