     * - /paws (PostHog)
     * - /tunnel (Sentry)
     * Feel free to modify this pattern to include more paths.
     */
    "/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)|paws|tunnel$).*)"
  ]
};

